import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { gameAPI } from '../utils/api';
import LoadingSpinner from '../components/LoadingSpinner';
import Confetti from 'react-confetti';

const GamePlay = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [game, setGame] = useState(null);
  const [loading, setLoading] = useState(true);
  const [playing, setPlaying] = useState(false);
  const [completed, setCompleted] = useState(false);
  const [score, setScore] = useState(0);
  const [currentQ, setCurrentQ] = useState(0);
  const [showConfetti, setShowConfetti] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState(null);
  const [showResult, setShowResult] = useState(false);

  useEffect(() => {
    gameAPI.getOne(id)
      .then(res => setGame(res.data.game))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [id]);

  const startGame = () => setPlaying(true);

  const handleQuizAnswer = (ansIdx) => {
    if (showResult) return;
    setSelectedAnswer(ansIdx);
    setShowResult(true);
    const content = game?.localizedContent;
    const isCorrect = ansIdx === content?.questions[currentQ]?.correctAnswer;
    if (isCorrect) setScore(s => s + 10);
  };

  const nextQuestion = () => {
    const total = game?.localizedContent?.questions?.length || 0;
    if (currentQ < total - 1) {
      setCurrentQ(c => c + 1);
      setSelectedAnswer(null);
      setShowResult(false);
    } else {
      finishGame();
    }
  };

  const finishGame = async () => {
    try {
      await gameAPI.complete({ gameId: id, score });
      setCompleted(true);
      setShowConfetti(true);
      setTimeout(() => setShowConfetti(false), 5000);
    } catch (err) { console.error(err); }
  };

  if (loading) return <LoadingSpinner />;
  if (!game) return <div className="dashboard"><h2>Game not found</h2></div>;

  const content = game.localizedContent;
  const isQuiz = game.gameType === 'image-quiz' || game.gameType === 'true-false';

  if (completed) {
    return (
      <div className="game-container">
        {showConfetti && <Confetti width={window.innerWidth} height={window.innerHeight} recycle={false} />}
        <motion.div className="card" style={{ textAlign: 'center', padding: 60 }} initial={{ scale: 0 }} animate={{ scale: 1 }}>
          <div style={{ fontSize: 80 }}>🏆</div>
          <h2>Game Complete!</h2>
          <p style={{ fontSize: 24, margin: '20px 0', fontWeight: 700 }}>Score: {score}</p>
          <p>⭐ +{game.xpReward} XP earned! 🪙 +{game.coinReward} Coins!</p>
          <div style={{ display: 'flex', gap: 20, justifyContent: 'center', marginTop: 30 }}>
            <button className="btn btn-primary" onClick={() => navigate('/games')}>🎮 More Games</button>
            <button className="btn btn-secondary" onClick={() => navigate('/dashboard')}>🏠 Dashboard</button>
          </div>
        </motion.div>
      </div>
    );
  }

  if (!playing) {
    return (
      <div className="game-container">
        <motion.div className="card" style={{ textAlign: 'center', padding: 60 }} initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
          <div style={{ fontSize: 80 }}>🎮</div>
          <h2>{game.localizedTitle || 'Fun Game'}</h2>
          <p style={{ margin: '20px 0', fontSize: 18 }}>{game.localizedInstructions}</p>
          <p style={{ color: '#666', marginBottom: 20 }}>Rewards: ⭐ {game.xpReward} XP + 🪙 {game.coinReward} Coins</p>
          <button className="btn btn-primary btn-lg pulse-anim" onClick={startGame}>🚀 Start Game!</button>
        </motion.div>
      </div>
    );
  }

  if (isQuiz) {
    const q = content?.questions?.[currentQ];
    if (!q) return <div>No questions</div>;
    return (
      <div className="game-container">
        <div className="game-header">
          <h2>{game.localizedTitle}</h2>
          <p>Question {currentQ + 1} of {content?.questions?.length}</p>
        </div>
        <div className="game-area">
          {q.imageUrl && <img src={q.imageUrl} alt="quiz" style={{ width: 200, height: 200, objectFit: 'cover', borderRadius: 12, marginBottom: 20 }} />}
          <p style={{ fontSize: 22, fontWeight: 700 }}>{q.questionText}</p>
          {q.hint && <p style={{ color: '#666', marginTop: 10 }}>💡 Hint: {q.hint}</p>}
          <div className="quiz-options">
            {q.options?.map((opt, i) => (
              <button key={i}
                className={`quiz-option ${showResult ? (i === q.correctAnswer ? 'correct' : i === selectedAnswer ? 'wrong' : '') : ''}`}
                onClick={() => handleQuizAnswer(i)} disabled={showResult}>
                {opt}
              </button>
            ))}
          </div>
          {showResult && (
            <div style={{ marginTop: 20 }}>
              <p style={{ color: selectedAnswer === q.correctAnswer ? '#4CAF50' : '#f44336', fontWeight: 700 }}>
                {selectedAnswer === q.correctAnswer ? '✅ Correct!' : '❌ Wrong'}
              </p>
              <button className="btn btn-primary" style={{ marginTop: 15 }} onClick={nextQuestion}>
                {currentQ < content.questions.length - 1 ? 'Next →' : '🎉 Finish'}
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  // Memory Card Game
  if (game.gameType === 'memory-card') {
    const cards = content?.cards || [];
    return (
      <div className="game-container">
        <div className="game-header">
          <h2>{game.localizedTitle}</h2>
          <p>Match the pairs!</p>
        </div>
        <div className="game-area">
          <div className="memory-grid">
            {cards.map((card, i) => (
              <div key={i} className={`memory-card flipped`}>
                {card.label?.[0] || '?'}
              </div>
            ))}
          </div>
          <button className="btn btn-primary" style={{ marginTop: 30 }} onClick={finishGame}>Complete Game</button>
        </div>
      </div>
    );
  }

  // Word Puzzle
  if (game.gameType === 'word-puzzle') {
    const puzzle = content?.puzzle;
    return (
      <div className="game-container">
        <div className="game-header">
          <h2>{game.localizedTitle}</h2>
        </div>
        <div className="game-area">
          <div style={{ fontSize: 48, letterSpacing: 20, fontWeight: 700 }}>{puzzle?.scrambled}</div>
          <p style={{ margin: '20px 0', color: '#666' }}>💡 Hint: {puzzle?.hint}</p>
          <div className="input-group" style={{ maxWidth: 300 }}>
            <input placeholder="Type the word..." />
          </div>
          <button className="btn btn-primary" style={{ marginTop: 20 }} onClick={finishGame}>Check Answer</button>
        </div>
      </div>
    );
  }

  // Default game view
  return (
    <div className="game-container">
      <div className="game-header">
        <h2>{game.localizedTitle}</h2>
      </div>
      <div className="game-area">
        <p style={{ fontSize: 20 }}>Get ready to play!</p>
        <button className="btn btn-primary btn-lg" style={{ marginTop: 30 }} onClick={finishGame}>🎉 Complete Game</button>
      </div>
    </div>
  );
};

export default GamePlay;
